#include<bits/stdc++.h>
using namespace std;

const int N = 1e5 + 5;

int dfn[N], low[N], flag[N], dfncnt, ans;
vector<int> e[N];

void tarjan(int u, int root) {
    low[u] = dfn[u] = ++dfncnt;
    int chd = 0;

    for (int v : e[u]) {
        if (!dfn[v]) {
            tarjan(v, root);
            low[u] = min(low[u], low[v]);
            chd++;

            if (u != root && low[v] >= dfn[u] && !flag[u]) {
                flag[u] = 1;
                ans++;
            }
        } 
        else {
            low[u] = min(low[u], dfn[v]);
        }
    }

    if (u == root && chd >= 2 && !flag[u]) {
        flag[u] = 1;
        ans++;
    }
}

int main() {
    int n, m;
    cin >> n >> m;

    for(int i = 1; i <= m; i++) {
        int u, v;
        cin >> u >> v;
        e[u].push_back(v);
        e[v].push_back(u);
    }

    for(int i = 1; i <= n; i++) {
        if(!dfn[i]) {
            tarjan(i, i);
        }
    }

    cout << ans << endl;
    for(int i = 1; i <= n; i++) {
        if(flag[i]) cout << i << ' ';
    }

    return 0;
}
